from agno.agent import Agent

supervisor = Agent(
    model=OpenAIChat(id="gpt-4o"),
    name="EmailSupervisor",
    instructions="Review drafts for: PII, tone, accuracy, confidentiality. Approve or reject."
)

def approve_draft(draft: dict, original_email: str):
    context = f"Original: {original_email}\nDraft: {draft}"
    decision = supervisor.run(context)
    return 'approved' in decision.lower()

