from vex import verify, Guardrail

pii_guardrail = Guardrail(
    name="pii_filter",
    checks=[
        "detect_pii(entities=['SSN', 'EMAIL', 'PHONE', 'ADDRESS'])"
    ]
)

@verify(guards=[pii_guardrail])
def safe_draft_generation(email_content: str) -> dict:
    result = draft_agent.run(email_content)
    return result

# Usage
clean_draft = safe_draft_generation(raw_email)

tone_guardrail = Guardrail(
    name="tone_check",
    checks=[
        "sentiment(toxicity<0.1, confidence>0.8, professional=True)",
        "regex(toxicity_phrases, match=none)"
    ]
)

@verify(guards=[tone_guardrail])
def verify_tone(draft: dict):
    result = supervisor.run(f"Review tone: {draft['body']}")
    return result

approved = verify_tone(draft_output)

full_pipeline = Guardrail(
    name="email_pipeline",
    checks=[
        "pii_filter",
        "tone_check",
        "recipient_validation(domain=['company.com', 'partner.org'])",
        "accuracy_check(factual_consistency>0.9)"
    ]
)

@vex.verify(guards=[full_pipeline])
def process_complete_email(email_data: dict):
    intent = email_agent.run(email_data['content'])
    draft = draft_agent.run(email_data['content'])
    approved = supervisor.run(str(draft))
    return {'intent': intent, 'draft': draft, 'approved': approved}
